# Memory Leaking in Rust with `Box::leak`

## The Function

```rust
use std::collections::HashMap;
use std::sync::OnceLock;

/// Represents application configuration loaded once at startup
#[derive(Debug)]
pub struct AppConfig {
    pub database_url: String,
    pub max_connections: u32,
    pub feature_flags: HashMap<String, bool>,
}

impl AppConfig {
    pub fn new(database_url: impl Into<String>, max_connections: u32) -> Self {
        let mut feature_flags = HashMap::new();
        feature_flags.insert("dark_mode".to_string(), true);
        feature_flags.insert("beta_features".to_string(), false);

        AppConfig {
            database_url: database_url.into(),
            max_connections,
            feature_flags,
        }
    }
}

impl Drop for AppConfig {
    fn drop(&mut self) {
        // This will NEVER be called when leaked — demonstrating the leak
        println!("AppConfig dropped (you won't see this if leaked)");
    }
}

/// Leaks a value and returns a `&'static` reference.
///
/// # When appropriate:
/// - The value must live for the entire program lifetime
/// - You need a `&'static` reference (e.g., for thread spawning, global state)
/// - The overhead of Arc/Mutex is undesirable for truly immutable global data
///
/// # When NOT appropriate:
/// - In loops or any repeated call path
/// - For large or frequently changing data
/// - When the lifetime is shorter than the program
pub fn leak_config(config: AppConfig) -> &'static AppConfig {
    Box::leak(Box::new(config))
}

